document.addEventListener('DOMContentLoaded',function(){var b=document.getElementById('random-locations-box'),h=document.getElementById('random-locations-handle');if(!b||!h)return;function t(){b.classList.toggle('open');h.setAttribute('aria-expanded',b.classList.contains('open')?'true':'false')}h.addEventListener('click',t);h.addEventListener('keydown',function(e){if(e.key==='Enter'||e.key===' '){e.preventDefault();t()}})});